const EPS=1e-9;export const CURRENCY_SETS=Object.freeze({USD:Object.freeze({symbol:"$",name:"USD",places:2,units:Object.freeze([{value:100,label:"$100"},{value:50,label:"$50"},{value:20,label:"$20"},{value:10,label:"$10"},{value:5,label:"$5"},{value:2,label:"$2"},{value:1,label:"$1"},{value:.25,label:"Quarter"},{value:.1,label:"Dime"},{value:.05,label:"Nickel"},{value:.01,label:"Penny"}]),minCoin:.1}),EUR:Object.freeze({symbol:"€",name:"EUR",places:2,units:Object.freeze([{value:500,label:"€500"},{value:200,label:"€200"},{value:100,label:"€100"},{value:50,label:"€50"},{value:20,label:"€20"},{value:10,label:"€10"},{value:5,label:"€5"},{value:2,label:"€2"},{value:1,label:"€1"},{value:.5,label:"50c"},{value:.2,label:"20c"},{value:.1,label:"10c"},{value:.05,label:"5c"},{value:.02,label:"2c"},{value:.01,label:"1c"}]),minCoin:.1}),JPY:Object.freeze({symbol:"¥",name:"JPY",places:0,units:Object.freeze([{value:1e4,label:"¥10000"},{value:5e3,label:"¥5000"},{value:2e3,label:"¥2000"},{value:1e3,label:"¥1000"},{value:500,label:"¥500"},{value:100,label:"¥100"},{value:50,label:"¥50"},{value:10,label:"¥10"},{value:5,label:"¥5"},{value:1,label:"¥1"}]),minCoin:1}),CNY:Object.freeze({symbol:"¥",name:"CNY",places:1,units:Object.freeze([{value:100,label:"¥100"},{value:50,label:"¥50"},{value:20,label:"¥20"},{value:10,label:"¥10"},{value:5,label:"¥5"},{value:1,label:"¥1"},{value:.5,label:"5jiao"},{value:.1,label:"1jiao"}]),minCoin:.1})});export function getCurrency(e){return CURRENCY_SETS[e]||CURRENCY_SETS.USD}export function parseInput(e){if(!e||"string"!=typeof e)return null;const l=e.trim();let a;if(l.includes(" "))a=l.split(/\s+/);else if(l.includes("/"))a=l.split("/");else if(l.includes("+"))a=l.split("+");else{if(!l.includes(","))return null;a=l.split(",")}if(a.length<2)return null;const t=parseFloat(a[0]),n=parseFloat(a[1]);return isNaN(t)||isNaN(n)||t<0||n<0?null:{price:Math.round(100*t)/100,paid:Math.round(100*n)/100}}export function greedy(e,l=CURRENCY_SETS.USD.units,a=1/0){let t=e;const n=[];for(const e of l){if(t<e.value-EPS)continue;const l=Math.floor(t/e.value+EPS),u=Math.min(l,a);if(u>0&&(n.push({value:e.value,label:e.label,count:u}),t=+(t-e.value*u).toFixed(2)),t<EPS)break}return{items:n,remaining:t>EPS?t:0}}const DESCRIPTIONS={optimal:"Uses the fewest pieces possible. Best for fast cash transactions — count and hand over quickly.",balanced:"Spreads change across more denominations so you don't run out of small bills. Great for everyday wallet use.",practical:"Avoids tiny coins. Ideal when the receiver prefers fewer small coins in their pocket."};export function calculate(e,l,a="USD"){const t=getCurrency(a),n=+(+e).toFixed(t.places),u=+(+l).toFixed(t.places);if(isNaN(n)||isNaN(u)||n<0||u<0)return{status:"invalid",balance:0,plans:[],currency:a};const i=+(u-n).toFixed(t.places);if(Math.abs(i)<EPS)return{status:"exact",balance:0,plans:[],currency:a};if(i<0)return{status:"short",balance:i,plans:[],currency:a};const s=[{id:"optimal",name:"Optimal Plan",cap:1/0,filter:null},{id:"balanced",name:"Balanced Plan",cap:3,filter:null},{id:"practical",name:"Practical Plan",cap:1/0,filter:e=>e.value>=t.minCoin}].map(e=>{const l=e.filter?t.units.filter(e.filter):t.units;let a=greedy(i,l,e.cap);if("practical"===e.id&&a.remaining>EPS){a=greedy(i,t.units)}return{id:e.id,name:e.name,totalCount:a.items.reduce((e,l)=>e+l.count,0),typeCount:a.items.length,units:a.items.map(e=>({value:e.value,label:e.label,count:e.count})),desc:DESCRIPTIONS[e.id]}});return{status:"settled",balance:i,plans:s,currency:a}}